const defaults={theme:'light',sound:true,soundEffect:'wood',volume:.35,keyboard:true,nextKey:true,liveWpm:true,liveAccuracy:true,reducedMotion:false,runStats:['progress','liveWpm','avgWpm','accuracy']};
let settings={...defaults,...load(SETTINGS_KEY,defaults)}; if(!Array.isArray(settings.runStats))settings.runStats=['progress',...(settings.liveWpm?['liveWpm','avgWpm']:[]),...(settings.liveAccuracy?['accuracy']:[])]; let history=load(HISTORY_KEY,{version:1,runs:[]}), notes=load(NOTES_KEY,{version:1,items:[]}), view='speed', pressed=new Set(), keyFlash={}, swipeStart=null, audio, session=null, noteEchoUntil=0, study={raw:'',text:'',name:'pasted notes',type:'text',caps:'lower',punctuation:false,numbers:true,limitType:'full',length:0,words:0}, noteTabs=load('slaptap-note-drafts-v2',loadNoteTabs()), activeNoteId='', savedDraftState='', speedGoal=load(TEST_KEY,{type:'time',duration:30,words:25,caps:'lower',punctuation:false,numbers:true}), studyStep=1, didAutoStart=false;
function load(k,f){try{const v=JSON.parse(localStorage.getItem(k)||'null');return v&&typeof v==='object'?{...f,...v}:f}catch{return f}} function save(k,v){try{localStorage.setItem(k,JSON.stringify(v));return true}catch{return false}}
