function currentNoteTab(){if(!noteTabs.tabs?.length)noteTabs.tabs=[blankNoteTab()]; if(!noteTabs.activeId||!noteTabs.tabs.some(t=>t.id===noteTabs.activeId))noteTabs.activeId=noteTabs.tabs[0].id; return noteTabs.tabs.find(t=>t.id===noteTabs.activeId)}
