function normalizeNoteDraft(t){return String(t||'').replace(/\r\n?/g,'\n').replace(/[\t\f\v ]+/g,' ').replace(/ *\n */g,'\n')}
function notePath(t=currentNoteTab()){const names=[]; let cur=t, guard=0; while(cur&&guard++<20){names.unshift(cur.title?.trim()||'Untitled'); cur=(noteTabs.tabs||[]).find(x=>x.id===(cur.parentId||''))} return names.join(' / ')}
