function copyNoteTab(id){const t=(noteTabs.tabs||[]).find(t=>t.id===id); if(!t)return; const text=`${notePath(t)}\n\n${t.text||''}`.trim(); if(navigator.clipboard?.writeText)navigator.clipboard.writeText(text); else {const a=document.createElement('textarea'); a.value=text; document.body.appendChild(a); a.select(); document.execCommand('copy'); a.remove()}}
function showNoteTabMenu(id,x=window.innerWidth/2,y=96){const t=(noteTabs.tabs||[]).find(t=>t.id===id); if(!t)return; modal.innerHTML=`<div class="shade menuShade"><div class="tabMenu" role="menu" style="--x:${Math.min(x,window.innerWidth-190)}px;--y:${Math.min(y,window.innerHeight-180)}px"><strong>${html(t.title||'Untitled')}</strong><button data-tab-action="copy">Copy</button><button data-tab-action="duplicate">Duplicate</button><button class="dangerBtn" data-tab-action="delete">Delete</button></div></div>`; modal.querySelector('.shade').onclick=e=>{if(e.target.classList.contains('shade'))closeSettings()}; modal.querySelector('.tabMenu').onclick=e=>{const a=e.target.dataset.tabAction; if(!a)return; if(a==='copy')copyNoteTab(id); if(a==='duplicate')duplicateNoteTab(id); if(a==='delete'&&confirm('Delete this tab and its sub-tabs?'))deleteNoteTab(id); closeSettings(); renderNotes()}}

function noteSnapshot(t=currentNoteTab()){return JSON.stringify({title:t.title||'',text:t.text||''})}
function hasUnsavedNoteChanges(){return (noteTabs.tabs||[]).some(t=>(t.text||'').trim()&&!t.saved&&!t.downloaded)}
function visualKeyboardStyle(){return settings.soundEffect==='none'?settings.theme:settings.soundEffect}
function applyTheme(){document.documentElement.dataset.theme=settings.theme;document.documentElement.dataset.keyboard=visualKeyboardStyle();document.documentElement.classList.toggle('reduced',settings.reducedMotion||matchMedia('(prefers-reduced-motion: reduce)').matches)} applyTheme();
function shuffle(a){const c=[...a];for(let i=c.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[c[i],c[j]]=[c[j],c[i]]}return c}
function notePhrases(){return (notes.items||[]).flatMap(n=>normalize(n.text).split(/\n+|(?<=[.!?])\s+/).map(x=>x.trim()).filter(x=>wordsOf(x).length>=3)).slice(0,80)}
