function canSwipeFrom(target){return target.closest('input,textarea,select,button,label,.viewport,.keyboard,.settingsDialog,.tabMenu')||modal.innerHTML}
function swipeDirection(dx,dy,dt){const adx=Math.abs(dx), ady=Math.abs(dy), velocity=adx/Math.max(dt,1); if(adx<SWIPE_MIN_DISTANCE||ady>SWIPE_MAX_OFF_AXIS||adx<ady*1.6||velocity<SWIPE_MIN_VELOCITY)return 0; return dx>0?1:-1}
