function initSwipeNav(){document.addEventListener('pointerdown',e=>{if(e.pointerType==='mouse'||canSwipeFrom(e.target))return; swipeStart={x:e.clientX,y:e.clientY,t:performance.now(),id:e.pointerId}}); document.addEventListener('pointerup',e=>{if(!swipeStart||swipeStart.id!==e.pointerId)return; const dir=swipeDirection(e.clientX-swipeStart.x,e.clientY-swipeStart.y,performance.now()-swipeStart.t); swipeStart=null; if(dir)goSwipe(dir)}); document.addEventListener('pointercancel',()=>{swipeStart=null})}
function isMobile(){return matchMedia('(max-width:720px), (pointer:coarse)').matches}
