function positionMobileInput(){if(!isMobile())return; const v=$('#viewport'), r=v?.getBoundingClientRect(); if(!r)return; input.style.top=`${Math.max(72,Math.min(r.top+24,innerHeight*.52))}px`; input.style.bottom='auto'}
