function hidePhoneKeyboard(){input.blur(); if(document.activeElement&&document.activeElement.blur)document.activeElement.blur()}
function saveTest(){save(TEST_KEY,speedGoal); study.limitType=speedGoal.type; study.length=speedGoal.duration; study.words=speedGoal.words}
function currentTestLabel(){return speedGoal.type==='time'?`${speedGoal.duration}s`:`${speedGoal.words} words`}
