class TypingSession{constructor({mode,target,duration,label,sourceName}){Object.assign(this,{mode,target,duration,label,sourceName,status:'ready',pos:0,typed:[],events:[],start:0,last:0,now:0,timer:null,samples:[],mistakes:[],saved:false,tab:false})} elapsed(){return this.start?(this.status==='finished'?this.now:(performance.now()-this.start))/1000:0} remaining(){return this.duration?Math.max(0,this.duration-this.elapsed()):0} stats(){return calc(this)} finish(){if(this.status==='finished')return;this.now=performance.now()-this.start;this.status='finished';clearInterval(this.timer);hidePhoneKeyboard();renderResults(this.stats())}}
