function observe(s){const m=mistyped(s)[0], dw=difficultWords(s,250)[0]; if(m)return`most errors involved “${m.label}”`; if(dw&&dw.label.length>8)return'you slowed down most on longer words'; if(s.target.includes('\n'))return'paragraph breaks created natural pauses'; return'your speed stayed very consistent'}
function keyChar(e){if(e.ctrlKey||e.metaKey||e.altKey||['Shift','Control','Alt','Meta','CapsLock'].includes(e.key))return null; if(e.key==='Enter')return'\n'; if(e.key==='Tab')return'\t'; if(e.key.length===1)return e.key; return null}
window.addEventListener('keydown',e=>{pressed.add(e.code); updateKeys(); if(e.key==='Escape'){if(modal.innerHTML)closeSettings(); else if(session&&session.status!=='finished')cancelTest(); return} if(isMobile()&&e.target===input)return; if(!session||session.status==='finished')return; if(e.key==='Tab'){session.tab=true; e.preventDefault(); return} if(session.tab&&e.key==='Enter'){e.preventDefault(); restartRun(session.mode); return} if([' ','PageDown','PageUp'].includes(e.key))e.preventDefault(); if(e.repeat)return; const ch=keyChar(e); if(e.key==='Backspace'){typeBack(); play('backspace','Backspace'); e.preventDefault()} else if(ch){const correct=typeIn(ch); play(correct===false?'wrong':ch===' '?'space':ch==='\n'?'enter':'char',ch); e.preventDefault()}});
window.addEventListener('keyup',e=>{pressed.delete(e.code); updateKeys()}); window.addEventListener('blur',()=>{pressed.clear();updateKeys()}); input.addEventListener('beforeinput',e=>{if(!isMobile()||!session||session.status==='finished')return; const t=e.inputType; if(t==='deleteContentBackward'){typeBack();play('backspace','Backspace')} else if(e.data){for(const ch of e.data){const correct=typeIn(ch);play(correct===false?'wrong':ch===' '?'space':ch==='\n'?'enter':'char',ch)}} e.preventDefault(); input.value=''});
input.addEventListener('input',()=>{if(isMobile()&&session&&session.status!=='finished'&&input.value){for(const ch of input.value){const correct=typeIn(ch);play(correct===false?'wrong':ch===' '?'space':ch==='\n'?'enter':'char',ch)}} input.value=''; keepTypingAreaVisible()});
