if(window.visualViewport){visualViewport.addEventListener('resize',()=>setTimeout(keepTypingAreaVisible,80)); visualViewport.addEventListener('scroll',()=>setTimeout(keepTypingAreaVisible,80))}
function typeIn(ch){const s=session;if(!s||s.status==='finished')return null; if(!s.duration&&s.pos>=s.target.length){s.finish();return true} if(s.status==='ready'){s.status='running';s.start=performance.now();s.last=s.start;s.timer=setInterval(tick,200)} const now=performance.now(), expected=s.target[s.pos]||''; const correct=ch===expected; s.typed.push(ch); s.events.push({time:now-s.start,expected,typed:ch,pos:s.pos,correct,corrected:false,word:wordAt(s.target,s.pos),delta:now-s.last}); flashKey(ch,correct); if(!correct)s.mistakes.push({time:(now-s.start)/1000,pos:s.pos}); s.pos++; s.last=now; if(s.mode==='speed'&&s.duration&&s.target.length-s.pos<800)s.target+=' '+speedTarget(); if((!s.duration&&s.pos>=s.target.length)||(s.duration&&s.elapsed()>=s.duration))s.finish(); else {renderText();liveStats();} return correct}
