function codeForChar(ch){if(typeof ch!=='string'||!ch)return''; return ch==='Backspace'?'Backspace':ch===' '?'Space':ch==='\n'?'Enter':/[a-zA-Z]/.test(ch)?`Key${ch.toUpperCase()}`:/[0-9]/.test(ch)?`Digit${ch}`:{'-':'Minus','=':'Equal','[':'BracketLeft',']':'BracketRight','\\':'Backslash',';':'Semicolon',"'":'Quote',',':'Comma','.':'Period','/':'Slash','`':'Backquote'}[ch]||''}
