function wordAt(t,p){const l=t.lastIndexOf(' ',p-1)+1, r=t.indexOf(' ',p);return t.slice(l,r<0?t.length:r).replace(/\n/g,' ')}
function tick(){if(!session)return; liveStats(); const e=session.elapsed(); if(Math.floor(e)>session.samples.length){const recent=session.events.filter(x=>x.typed!=='Backspace'&&x.time/1000>e-5), c=recent.filter(x=>x.correct).length; session.samples.push({time:Math.floor(e),wpm:Math.round(c/5/(Math.min(5,e)/60)),mistakes:session.mistakes.filter(m=>m.time>e-1&&m.time<=e).length})} if(session.duration&&e>=session.duration)session.finish()}
function renderSpeed(){if(!didAutoStart){didAutoStart=true;startSpeed();return} screen.innerHTML=`<section class="panel"><div class="hero"><p class="eyebrow">speed mode</p><h1>Fast words. Honest scores.</h1><p>Choose a timed run or a Monkeytype-style word count, then customize capitalization, punctuation, and numbers.</p></div><div class="options speedOptions"><label>Test type<select id="speedType"><option value="time" ${speedGoal.type==='time'?'selected':''}>Time</option><option value="words" ${speedGoal.type==='words'?'selected':''}>Words</option></select></label><label class="speedTime">Time<select id="speedDuration">${DURATIONS.map(d=>`<option value="${d}" ${speedGoal.duration===d?'selected':''}>${d}s</option>`).join('')}</select></label><label class="speedWords">Words<select id="speedWordCount">${SPEED_WORDS.map(w=>`<option value="${w}" ${speedGoal.words===w?'selected':''}>${w} words</option>`).join('')}</select></label><label>Capitals<select id="speedCaps"><option value="lower" ${speedGoal.caps==='lower'?'selected':''}>remove capitals</option><option value="keep" ${speedGoal.caps==='keep'?'selected':''}>keep original</option><option value="upper" ${speedGoal.caps==='upper'?'selected':''}>ALL CAPITALS</option></select></label><label><input id="speedPunctuation" type="checkbox" ${speedGoal.punctuation?'checked':''}/> Punctuation</label><label><input id="speedNumbers" type="checkbox" ${speedGoal.numbers?'checked':''}/> Numbers</label></div><button class="primary" id="goSpeed">Start ${speedGoal.type==='time'?speedGoal.duration+'s':speedGoal.words+' word'} speed run</button></section>`; const sync=()=>{document.querySelector('.speedTime').style.display=speedGoal.type==='time'?'block':'none';document.querySelector('.speedWords').style.display=speedGoal.type==='words'?'block':'none';$('#goSpeed').textContent=`Start ${speedGoal.type==='time'?speedGoal.duration+'s':speedGoal.words+' word'} speed run`}; sync(); $('#speedType').onchange=e=>{speedGoal.type=e.target.value;saveTest();sync()}; $('#speedDuration').onchange=e=>{speedGoal.duration=Number(e.target.value);saveTest();sync()}; $('#speedWordCount').onchange=e=>{speedGoal.words=Number(e.target.value);saveTest();sync()}; $('#speedCaps').onchange=e=>{speedGoal.caps=e.target.value;saveTest()}; $('#speedPunctuation').onchange=e=>{speedGoal.punctuation=e.target.checked;saveTest()}; $('#speedNumbers').onchange=e=>{speedGoal.numbers=e.target.checked;saveTest()}; $('#goSpeed').onclick=()=>startSpeed()}
function statLabel(id){return (RUN_STATS.find(s=>s[0]===id)||[])[1]||id}
function renderRunStats(){const chosen=(settings.runStats||defaults.runStats).filter(id=>RUN_STATS.some(s=>s[0]===id)); return `${chosen.map(id=>`<div class="stat"><span>${html(id==='progress'?(session?.duration?'time':'words'):statLabel(id))}</span><strong data-run-stat="${id}">0</strong></div>`).join('')}<button class="ghost addStatButton" id="addStat" aria-label="Add or change stats" title="Add or change stats">+</button>`}
function renderRun(){screen.innerHTML=`<section class="run"><div class="runHead"><div class="liveStats">${renderRunStats()}</div><button class="ghost cancelTest" id="cancelTest">Cancel test</button></div><div class="typingBar"><div class="viewport" id="viewport"><div class="words" id="words"></div></div></div><p class="hint">${isMobile()?'Tap the words, then type with your phone keyboard.':'Timer starts on your first key · Tab then Enter restarts · Esc cancels'}</p><div id="mobileControls"></div><div id="keyboardHost"></div></section>`; $('#viewport').onclick=()=>focusInput(true); $('#cancelTest').onclick=cancelTest; $('#addStat').onclick=openStatPicker; renderText(); liveStats(); renderMobileControls(); renderKeyboard(); focusInput()}
function renderText(){const w=$('#words'); if(!w||!session)return; positionMobileInput(); const start=Math.max(0,session.pos-650), end=Math.min(session.target.length,session.pos+1200); let out='', open=false; const close=()=>{if(open){out+='</span>';open=false}}; for(let i=start;i<end;i++){const t=session.target[i], typed=session.typed[i], cls=i<session.pos?(typed===t?'correct':'wrong'):'pending', cur=i===session.pos?'current':''; if(/\s/.test(t)){close(); out+=`<span class="char space ${cls} ${cur}" data-i="${i}">${t==='\n'?'↵\n':' '}</span>`} else {if(!open){out+='<span class="word">';open=true} out+=`<span class="char ${cls} ${cur}" data-i="${i}">${html(t)}</span>`}} close(); w.innerHTML=out; requestAnimationFrame(()=>{const cur=w.querySelector('.current'); if(cur){const line=parseFloat(getComputedStyle(w).lineHeight)||42, target=Math.max(0,cur.offsetTop-line); w.style.transform=`translateY(${-target}px)`; keepTypingAreaVisible()}})}
function currentStreak(s){let n=0; for(let i=s.events.length-1;i>=0;i--){const e=s.events[i]; if(e.typed==='Backspace')continue; if(!e.correct)break; n++} return n}
function liveStats(){if(!session)return; const st=session.stats(), values={progress:session.duration?`${Math.ceil(session.remaining())}s`:`${wordsOf(session.target.slice(0,session.pos)).length}/${wordsOf(session.target).length}`,liveWpm:liveRecentWpm(session),avgWpm:st.wpm,accuracy:`${st.accuracy}%`,rawWpm:st.rawWpm,correct:st.correct,incorrect:st.incorrect,streak:currentStreak(session),remainingChars:Math.max(0,session.target.length-session.pos)}; document.querySelectorAll('[data-run-stat]').forEach(el=>el.textContent=values[el.dataset.runStat]??0)}
function openStatPicker(){hidePhoneKeyboard(); const picked=new Set(settings.runStats||defaults.runStats); modal.innerHTML=`<div class="shade"><dialog open class="settingsDialog"><div class="settingsHead"><div><p class="eyebrow">test stats</p><h2>Live test stats</h2><p class="hint">Choose the stats shown during Speed and Study/notes tests. Uncheck and re-check a stat to move it to the end.</p></div><button id="closeStatsTop" class="ghost iconBtn" aria-label="Close stats">×</button></div><div class="statPicker">${RUN_STATS.map(([id,label])=>`<label><input type="checkbox" data-stat-pick="${id}" ${picked.has(id)?'checked':''}/><span>${html(label)}</span></label>`).join('')}</div><div class="settingsActions"><button id="resetStats" class="ghost">Reset stats</button><button id="doneStats" class="primary">Done</button></div></dialog></div>`; document.querySelectorAll('[data-stat-pick]').forEach(box=>box.onchange=e=>{const id=e.target.dataset.statPick; let next=(settings.runStats||defaults.runStats).filter(x=>x!==id); if(e.target.checked)next.push(id); settings.runStats=next; save(SETTINGS_KEY,settings)}); $('#resetStats').onclick=()=>{settings.runStats=[...defaults.runStats];save(SETTINGS_KEY,settings);openStatPicker()}; $('#closeStatsTop').onclick=$('#doneStats').onclick=()=>{closeSettings(); if(session&&session.status!=='finished')renderRun()}}
function cancelTest(){if(!session)return; clearInterval(session.timer); const mode=session.mode; session=null; hidePhoneKeyboard(); view=mode==='study'?'study':'speed'; render()}
function renderKeyboard(){const h=$('#keyboardHost'); if(!h)return; applyTheme(); if(isMobile()){h.innerHTML='';return;} if(!settings.keyboard){h.innerHTML='<button class="ghost" id="showKb">show keyboard</button>'; $('#showKb').onclick=()=>{settings.keyboard=true;save(SETTINGS_KEY,settings);renderKeyboard()};return} const rows=[['Backquote','Digit1','Digit2','Digit3','Digit4','Digit5','Digit6','Digit7','Digit8','Digit9','Digit0','Minus','Equal','Backspace'],['Tab','KeyQ','KeyW','KeyE','KeyR','KeyT','KeyY','KeyU','KeyI','KeyO','KeyP','BracketLeft','BracketRight','Backslash'],['CapsLock','KeyA','KeyS','KeyD','KeyF','KeyG','KeyH','KeyJ','KeyK','KeyL','Semicolon','Quote','Enter'],['ShiftLeft','KeyZ','KeyX','KeyC','KeyV','KeyB','KeyN','KeyM','Comma','Period','Slash','ShiftRight'],['Space']]; const labels={Backspace:'⌫',Tab:'tab',CapsLock:'caps',Enter:'enter',ShiftLeft:'shift',ShiftRight:'shift',Space:'space',Backquote:'`',Minus:'-',Equal:'=',BracketLeft:'[',BracketRight:']',Backslash:'\\',Semicolon:';',Quote:"'",Comma:',',Period:'.',Slash:'/'}; h.innerHTML=`<div class="kbTop"><span>${html(KEY_SOUNDS[settings.soundEffect]||THEMES[settings.theme]||'Visual')} visual keyboard</span><button class="ghost" id="hideKb">minimize</button></div><div class="keyboard">${rows.map(r=>`<div class="kbRow">${r.map(c=>`<kbd data-code="${c}" class="${c}">${labels[c]||c.replace('Key','').replace('Digit','')}</kbd>`).join('')}</div>`).join('')}</div>`; $('#hideKb').onclick=()=>{settings.keyboard=false;save(SETTINGS_KEY,settings);renderKeyboard()}; updateKeys()}
function renderMobileControls(){const h=$('#mobileControls'); if(!h)return; h.innerHTML=isMobile()?'<div class="mobilePad"><button class="ghost" id="tapRestart">Restart run</button></div>':''; const r=$('#tapRestart'); if(r)r.onclick=()=>restartRun(session?.mode)}
function updateKeys(){document.querySelectorAll('kbd').forEach(k=>{k.classList.toggle('down',pressed.has(k.dataset.code)); k.classList.toggle('hit',keyFlash[k.dataset.code]==='hit'); k.classList.toggle('miss',keyFlash[k.dataset.code]==='miss')}); if(settings.nextKey&&session){const code=codeForChar(session.target[session.pos]); document.querySelectorAll('kbd').forEach(k=>k.classList.toggle('next',k.dataset.code===code))}}
function limitStudyText(full=false){saveTest(); const text=study.text||''; return full?text:randomStudyExcerpt(text,speedGoal.words)}
function studyLabel(){return currentTestLabel()}
function selectStudyNote(n){if(!n)return; studyStep=2; setStudy(n.text,n.title||'saved note','saved note')}
function startStudyTest(full=false){if(study.text)begin(studyRunConfig(full))}
function renderStudy(){const hasText=!!study.text, text=study.raw, wc=wordsOf(study.text||text).length; if(!hasText)studyStep=1; const step=hasText?studyStep:1; const source=`<div class="studyStep active"><p class="eyebrow">step 1 of 2</p><h1>Study mode</h1><h2>Drop your notes here</h2><p class="hint">Add notes first. After that, tap Next to choose exactly how the test should work.</p><label class="drop" id="drop">Drop notes here<input id="file" type="file" accept=".txt,.md,.markdown,.rtf,.doc,.docx,.pdf,.html,.htm,.csv,.json,.xml,.log,text/*,application/pdf,application/rtf"/></label>${(notes.items||[]).length?`<label>Choose saved note<select id="studySavedNote"><option value="">Select a saved note...</option>${notes.items.map(n=>`<option value="${n.id}" ${study.type==='saved note'&&study.name===(n.title||'saved note')?'selected':''}>${html(n.title||'Untitled note')} · ${wordsOf(n.text).length} words</option>`).join('')}</select></label>`:'<p class="hint">Saved notes will appear here after you save them in Notes.</p>'}<label>Paste notes<textarea id="paste" class="paste" placeholder="Paste class notes here...">${html(study.raw)}</textarea></label><div class="actions"><button class="primary" id="studyNext" ${hasText?'':'disabled'}>Next</button><button class="ghost" id="clearStudy" ${hasText?'':'disabled'}>Clear notes</button></div><p id="fileMsg" class="hint"></p></div>`; const options=`<div class="studyStep active"><p class="eyebrow">step 2 of 2</p><h1>Choose test options</h1><p class="hint">Pick a test type, choose how many words should be pulled from a random section, then start. Full test starts from the beginning of your notes.</p><div class="preview"><strong>${html(study.name)}</strong> · ${html(study.type)} · ${wc} words · ${(study.text||text).length} chars · selected: ${html(studyLabel())}<p>${html(limitStudyText().slice(0,420))}</p></div><div class="options"><label>Test type<select id="studyTestType"><option value="time" ${speedGoal.type==='time'?'selected':''}>Time</option><option value="words" ${speedGoal.type==='words'?'selected':''}>Words</option></select></label><label class="studyTime">Time<select id="studyDuration">${DURATIONS.map(d=>`<option value="${d}" ${speedGoal.duration===d?'selected':''}>${d}s</option>`).join('')}</select></label><label>Amount of words<select id="studyWordCount">${SPEED_WORDS.map(w=>`<option value="${w}" ${speedGoal.words===w?'selected':''}>${w} words</option>`).join('')}</select></label><label><input id="studyPunctuation" type="checkbox" ${study.punctuation?'checked':''}/> Punctuation</label><label><input id="studyNumbers" type="checkbox" ${study.numbers?'checked':''}/> Numbers</label></div><div class="actions"><button class="ghost" id="studyBack">Back</button><button class="primary" id="startStudy">Start random section</button><button class="primary" id="startFullStudy">Do the full test</button><button class="ghost" id="clearStudy">Clear notes</button></div></div>`; screen.innerHTML=`<section class="panel study stepStudy">${step===1?source:options}</section>`; const clear=()=>{study={raw:'',text:'',name:'pasted notes',type:'text',caps:'lower',punctuation:false,numbers:true,limitType:'full',length:0,words:0};studyStep=1;renderStudy()}; const paste=$('#paste'); if(paste)paste.oninput=e=>setStudy(e.target.value,'pasted notes','text'); const savedSelect=$('#studySavedNote'); if(savedSelect)savedSelect.onchange=e=>selectStudyNote((notes.items||[]).find(n=>n.id===e.target.value)); const studyType=$('#studyTestType'), studyDuration=$('#studyDuration'), studyWordCount=$('#studyWordCount'); const syncStudyTest=()=>{const t=document.querySelector('.studyTime'); if(t)t.style.display=speedGoal.type==='time'?'block':'none'}; syncStudyTest(); if(studyType)studyType.onchange=e=>{speedGoal.type=e.target.value;saveTest();studyStep=2;syncStudyTest();renderStudy()}; if(studyDuration)studyDuration.onchange=e=>{speedGoal.duration=Number(e.target.value);saveTest();studyStep=2;renderStudy()}; if(studyWordCount)studyWordCount.onchange=e=>{speedGoal.words=Number(e.target.value);saveTest();studyStep=2;renderStudy()}; const punc=$('#studyPunctuation'); if(punc)punc.onchange=e=>{study.punctuation=e.target.checked;studyStep=2;setStudy(study.raw,study.name,study.type)}; const nums=$('#studyNumbers'); if(nums)nums.onchange=e=>{study.numbers=e.target.checked;studyStep=2;setStudy(study.raw,study.name,study.type)}; const start=$('#startStudy'); if(start)start.onclick=()=>startStudyTest(false); const fullStart=$('#startFullStudy'); if(fullStart)fullStart.onclick=()=>startStudyTest(true); const next=$('#studyNext'); if(next)next.onclick=()=>{studyStep=2;renderStudy()}; const back=$('#studyBack'); if(back)back.onclick=()=>{studyStep=1;renderStudy()}; document.querySelectorAll('#clearStudy').forEach(b=>b.onclick=clear); const file=$('#file'), drop=$('#drop'); if(file)file.onchange=e=>e.target.files[0]&&readFile(e.target.files[0]); if(drop){drop.ondragover=e=>{e.preventDefault();drop.classList.add('over')}; drop.ondragleave=()=>drop.classList.remove('over'); drop.ondrop=e=>{e.preventDefault();drop.classList.remove('over');readFile(e.dataTransfer.files[0])}}}
function setStudy(raw,name,type){study.raw=study.punctuation?normalize(raw):oneLineNotes(raw).trim();study.name=name;study.type=type;study.text=formatText(study.raw,study); renderStudy()}
async function readFile(f){const msg=()=>$('#fileMsg'); if(!f)return; if(f.size>MAX_FILE){msg().textContent='That file is too large for local browser extraction. Please paste a smaller section.';return} try{let ext=f.name.split('.').pop().toLowerCase(), txt=''; if(['txt','md','markdown','csv','html','htm','json','xml','log','rtf','doc'].includes(ext)){txt=await f.text(); if(['html','htm'].includes(ext))txt=new DOMParser().parseFromString(txt,'text/html').body.textContent||''; if(ext==='json')txt=JSON.stringify(JSON.parse(txt),null,2)} else if(ext==='docx') txt=await extractDocx(f); else if(ext==='pdf') txt=await extractPdf(f); else {txt=await f.text().catch(()=>''); if(!txt){msg().textContent='Unsupported file type. Please copy and paste the text.';return}} if(!normalize(txt)){msg().textContent='No extractable text found. Image-only or empty files may need copy and paste.';return} setStudy(txt,f.name,ext)}catch(err){msg().textContent='Text could not be extracted locally from this file. Try copy and paste instead.'}}
async function extractDocx(f){const buf=await f.arrayBuffer(), bytes=new Uint8Array(buf), text=new TextDecoder().decode(bytes); const m=[...text.matchAll(/word\/document\.xml[\s\S]*?<w:t[^>]*>(.*?)<\/w:t>/g)].map(x=>x[1]); if(m.length)return m.join(' ').replace(/&lt;/g,'<').replace(/&amp;/g,'&'); throw Error('docx extraction limited without optional mammoth dependency')}
async function extractPdf(f){const raw=new TextDecoder('latin1').decode(await f.arrayBuffer()); return [...raw.matchAll(/\(([^()]{2,})\)\s*Tj/g)].map(m=>m[1].replace(/\\([()\\])/g,'$1')).join(' ')}
function graph(samples,avg){if(!samples.length)return'<p>No graph samples were recorded.</p>'; const w=620,h=180,max=Math.max(20,...samples.map(p=>p.wpm),avg), pts=samples.map((p,i)=>`${(i/(samples.length-1||1))*w},${h-(p.wpm/max)*(h-20)-10}`).join(' '), ay=h-(avg/max)*(h-20)-10; return `<svg class="graph" viewBox="0 0 ${w} ${h}" role="img" aria-label="Speed over time graph averaging ${avg} WPM"><line x1="0" x2="${w}" y1="${ay}" y2="${ay}" class="avg"/><polyline points="${pts}"/><g>${samples.map((p,i)=>p.mistakes?`<circle cx="${(i/(samples.length-1||1))*w}" cy="${h-(p.wpm/max)*(h-20)-10}" r="3"/>`:'').join('')}</g></svg><p class="sr">Speed graph from ${samples[0].time}s to ${samples.at(-1).time}s.</p>`}
function list(title,items,suffix=''){return`<div class="card"><h3>${title}</h3>${items.length?items.map(i=>`<p><b>${html(i.label)}</b> <span>${i.value}${suffix}</span></p>`).join(''):'<p>Not enough data yet.</p>'}</div>`}
function renderResults(st){screen.innerHTML=`<section class="results"><p class="eyebrow">${st.mode} complete</p><h1>${st.wpm} wpm</h1><div class="resultGrid">${metric('raw wpm',st.rawWpm)}${metric('accuracy',st.accuracy+'%')}${metric('correct',st.correct)}${metric('incorrect',st.incorrect)}${metric('corrected',st.correctedErrors)}${metric('duration',st.duration+'s')}${metric('words',st.wordsCompleted)}${metric('consistency',st.consistency+'%')}</div>${graph(st.graph,st.wpm)}<p class="observation">${html(st.observation)}</p><div class="insights">${list('Difficult words',st.difficultWords,'ms')}${list('Slowest characters',st.slowestCharacters,'ms')}${list('Most mistyped',st.mistypedCharacters)}</div><label>Optional local label<input id="runLabel" maxlength="60" placeholder="chapter three review"/></label><div class="actions"><button class="primary" id="saveRun">Save run</button><button class="ghost" id="discardRun">Discard run</button><button class="ghost" id="tryRun">Try again</button><button class="ghost" id="newRun">New test</button></div><p class="hint">Study contents are not saved to history.</p></section>`; $('#saveRun').onclick=()=>saveRun(st); $('#discardRun').onclick=()=>{session=null; view=st.mode==='study'?'study':'speed'; render()}; $('#tryRun').onclick=()=>restartRun(st.mode); $('#newRun').onclick=()=>{view=st.mode==='study'?'study':'speed';render()}}
function saveRun(st){if(history.runs.length>=MAX_HISTORY){alert('History is full. Delete an older saved run before saving this one.');return} const rec={id:crypto.randomUUID(),createdAt:new Date().toISOString(),...st,sourceName:st.sourceName||'',userLabel:$('#runLabel').value.trim()}; history={version:1,runs:[rec,...history.runs]}; if(save(HISTORY_KEY,history)){session.saved=true; $('#saveRun').disabled=true; $('#saveRun').textContent='Saved'}}
function noteStats(text,started,wordTimes=[]){const elapsed=started?Math.max((performance.now()-started)/1000,.1):0, chars=text.length, words=wordsOf(text).length, recent=wordTimes.slice(-4), span=recent.length>1?(recent.at(-1)-recent[0])/1000:0, live=recent.length>1?Math.round(recent.length/(Math.max(span,.25)/60)):0; return {wpm:live,avgWpm:elapsed?Math.round(words/(elapsed/60)):0, words, chars, elapsed:Math.round(elapsed)}}
function downloadNote(n){const blob=new Blob([n.text],{type:'text/plain'}), a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=(n.title||'slaptap-note').replace(/[^a-z0-9-_ ]/gi,'_')+'.txt'; a.click(); URL.revokeObjectURL(a.href)}
function noteKeyKind(ch){return ch==='Backspace'?'backspace':ch===' '?'space':ch==='\n'?'enter':'char'}
function popNoteChar(ch,wrong=false){const body=$('#noteBody'); if(!body||!ch)return; const r=body.getBoundingClientRect(), host=body.closest('.notes')||screen, pop=document.createElement('span'); pop.className=`notePop ${wrong?'wrong':'good'}`; pop.textContent=ch==='\n'?'↵':ch===' '?'space':ch; const x=Math.min(r.right-38,Math.max(r.left+18,r.left+body.clientWidth*.54+(Math.random()-.5)*80)), y=Math.min(r.bottom-26,Math.max(r.top+24,r.top+body.clientHeight*.45+(Math.random()-.5)*70)); pop.style.left=`${x}px`; pop.style.top=`${y}px`; host.appendChild(pop); setTimeout(()=>pop.remove(),720)}
function noteFeedback(ch,wrong=false){play(wrong?'wrong':noteKeyKind(ch),ch); popNoteChar(ch,wrong)}
function wireNoteFeedback(body){body.addEventListener('keydown',e=>{if(e.ctrlKey||e.metaKey||e.altKey)return; if(e.repeat)return; if(e.key==='Backspace'){const removed=body.selectionStart===body.selectionEnd?body.value[body.selectionStart-1]:body.value.slice(body.selectionStart,body.selectionEnd).at(-1); noteFeedback(removed||'⌫',true); noteEchoUntil=performance.now()+80; return} const ch=keyChar(e); if(!ch)return; noteFeedback(ch,false); noteEchoUntil=performance.now()+80}); body.addEventListener('beforeinput',e=>{if(e.inputType==='insertLineBreak'||e.inputType==='insertParagraph'){noteFeedback('↵',false); return} if(e.inputType==='deleteContentBackward'&&(!e.isComposing)){if(performance.now()>=noteEchoUntil)noteFeedback('⌫',true);return} if(e.data&&(!e.isComposing)){if(performance.now()<noteEchoUntil)return; for(const ch of e.data)noteFeedback(ch,false)}}); body.addEventListener('paste',e=>{e.preventDefault(); const text=normalizeNoteDraft(e.clipboardData?.getData('text')||''); document.execCommand('insertText',false,text); for(const ch of text.slice(0,8))noteFeedback(ch,false)})}
function saveActiveNote({markDownloaded=false}={}){const tab=currentNoteTab(); tab.title=$('#noteTitle')?.value.trim()||tab.title; tab.text=$('#noteBody')?.value||tab.text; tab.updatedAt=new Date().toISOString(); if(markDownloaded)tab.downloaded=true; persistNoteTabs(); savedDraftState=noteSnapshot(tab)}
function renderNotes(){let started=0, noteWordTimes=[]; currentNoteTab(); savedDraftState=noteSnapshot(); const tab=currentNoteTab(); screen.innerHTML=`<section class="panel notes"><h1>Notes</h1><p class="hint">Type or paste notes here. Press Enter for a new line. Click the active tab again to open its sub-tabs.</p><div class="noteTabs"><button class="primary" id="newNoteTab">+ New note tab</button>${noteTabTree()}</div><label>Title<input id="noteTitle" maxlength="80" placeholder="Lecture notes" value="${html(tab.title)}"/></label><p class="activeNote">Working in: <strong id="activeNoteName">${html(notePath(tab))}</strong></p><div class="noteWrap"><textarea id="noteBody" class="paste notePad" spellcheck="false" placeholder="Start typing notes...">${html(tab.text)}</textarea></div><div class="resultGrid"><div class="stat"><span>live wpm</span><strong id="noteWpm">0</strong></div><div class="stat"><span>average wpm</span><strong id="noteAvgWpm">0</strong></div><div class="stat"><span>words</span><strong id="noteWords">0</strong></div><div class="stat"><span>characters</span><strong id="noteChars">0</strong></div></div><div class="actions"><button class="primary" id="saveNote">Save note</button><button class="primary" id="startNoteTest" ${tab.text.trim()?'':'disabled'}>Start test</button><button class="ghost" id="downloadDraft">Download draft</button><button class="ghost dangerBtn" id="clearNote">Clear draft</button></div><h2>Saved notes</h2><div id="savedNotes"></div></section>`; const body=$('#noteBody'), title=$('#noteTitle'), update=(touch=true)=>{if(touch&&!started)started=performance.now(); const tab=currentNoteTab(); const priorWords=wordsOf(tab.text).length; const stText=normalizeNoteDraft(body.value); tab.text=stText; if(body.value!==tab.text)body.value=tab.text; tab.title=title.value; tab.updatedAt=new Date().toISOString(); tab.saved=false; tab.downloaded=false; persistNoteTabs(); const nextWords=wordsOf(stText).length; if(touch&&nextWords>priorWords)for(let i=priorWords;i<nextWords;i++)noteWordTimes.push(performance.now()); const st=noteStats(stText,started,noteWordTimes); $('#noteWpm').textContent=st.wpm; $('#noteAvgWpm').textContent=st.avgWpm; const testBtn=$('#startNoteTest'); if(testBtn)testBtn.disabled=!tab.text.trim(); $('#noteWords').textContent=st.words; $('#noteChars').textContent=st.chars; const btn=screen.querySelector(`[data-note-tab="${tab.id}"]`); if(btn)btn.textContent=tab.title||'Untitled'; const active=$('#activeNoteName'); if(active)active.textContent=notePath(tab)}; const draw=()=>{$('#savedNotes').innerHTML=(notes.items||[]).map(n=>`<article class="history"><h3>${html(n.title||'Untitled note')} <small>${new Date(n.createdAt).toLocaleString()}</small></h3><p>${wordsOf(n.text).length} words · ${n.text.length} chars</p><p>${html(n.text.slice(0,220))}</p><button class="primary" data-test-note="${n.id}">Start test</button><button class="ghost" data-use-note="${n.id}">Use in Study</button><button class="ghost" data-down-note="${n.id}">Download</button><button class="ghost" data-del-note="${n.id}">Delete</button></article>`).join('')||'<p class="hint">No saved notes yet.</p>'}; body.oninput=update; title.oninput=update; wireNoteFeedback(body); $('#newNoteTab').onclick=()=>{saveActiveNote(); const t=blankNoteTab(); noteTabs.tabs.unshift(t); noteTabs.activeId=t.id; noteTabs.expandedId=''; persistNoteTabs(); renderNotes()}; screen.querySelectorAll('[data-note-tab]').forEach(b=>{let holdTimer=0, held=false; const open=e=>{e.preventDefault(); held=true; showNoteTabMenu(b.dataset.noteTab,e.clientX||window.innerWidth/2,e.clientY||96)}; b.oncontextmenu=open; b.onpointerdown=e=>{held=false; clearTimeout(holdTimer); holdTimer=setTimeout(()=>open(e),620)}; ['pointerup','pointercancel','pointerleave'].forEach(ev=>b.addEventListener(ev,()=>clearTimeout(holdTimer))); b.onclick=e=>{if(held){e.preventDefault(); return} e.preventDefault(); const y=window.scrollY; saveActiveNote(); if(noteTabs.activeId===b.dataset.noteTab)noteTabs.expandedId=noteTabs.expandedId===b.dataset.noteTab?'':b.dataset.noteTab; else {noteTabs.activeId=b.dataset.noteTab; noteTabs.expandedId=''} persistNoteTabs(); renderNotes(); requestAnimationFrame(()=>window.scrollTo({top:y,behavior:'auto'}))}}); screen.querySelectorAll('[data-new-subtab]').forEach(b=>b.onclick=e=>{e.preventDefault(); const y=window.scrollY; saveActiveNote(); const t=blankNoteTab(b.dataset.newSubtab); noteTabs.tabs.push(t); noteTabs.activeId=t.id; noteTabs.expandedId=b.dataset.newSubtab; persistNoteTabs(); renderNotes(); requestAnimationFrame(()=>window.scrollTo({top:y,behavior:'auto'}))}); $('#saveNote').onclick=()=>{const tab=currentNoteTab(); if(!tab.text.trim())return; if(notes.items.length>=MAX_NOTES)return alert('Note storage is full. Delete an older note first.'); notes={version:1,items:[{id:crypto.randomUUID(),createdAt:new Date().toISOString(),title:tab.title.trim(),text:tab.text},...(notes.items||[])]}; save(NOTES_KEY,notes); tab.saved=true; tab.downloaded=false; persistNoteTabs(); savedDraftState=noteSnapshot(tab); study={...study,raw:normalize(tab.text),text:formatText(tab.text,study),name:tab.title.trim()||'saved note',type:'note'}; draw(); const sb=$('#saveNote'); if(sb){sb.textContent='Saved ✓'; sb.disabled=true; setTimeout(()=>{if($('#saveNote')===sb){sb.textContent='Save note'; sb.disabled=false}},1400)}}; $('#startNoteTest').onclick=()=>{update(); const tab=currentNoteTab(); if(!tab.text.trim())return; study={...study,raw:normalize(tab.text),text:formatText(tab.text,study),name:tab.title.trim()||'current note',type:'note draft'}; startStudyTest()}; $('#downloadDraft').onclick=()=>{const tab=currentNoteTab(); downloadNote({title:tab.title.trim()||'slaptap-note',text:tab.text}); tab.downloaded=true; persistNoteTabs(); savedDraftState=noteSnapshot(tab)}; $('#clearNote').onclick=()=>{if(!confirm('Clear this draft? All text in this note tab will be deleted.'))return; const tab=currentNoteTab(); tab.text=''; tab.saved=true; tab.downloaded=true; body.value=''; started=performance.now(); persistNoteTabs(); update()}; $('#savedNotes').onclick=e=>{const down=e.target.dataset.downNote, del=e.target.dataset.delNote, use=e.target.dataset.useNote, test=e.target.dataset.testNote; if(use){const n=notes.items.find(n=>n.id===use); if(n){selectStudyNote(n); view='study'; renderStudy()}} if(test){const n=notes.items.find(n=>n.id===test); if(n){selectStudyNote(n); startStudyTest()}} if(down)downloadNote(notes.items.find(n=>n.id===down)); if(del&&confirm('Delete this saved note? This cannot be undone.')){notes.items=notes.items.filter(n=>n.id!==del);save(NOTES_KEY,notes);draw()}}; update(false); draw(); if(!isMobile())body.focus({preventScroll:true})}
function renderHistory(){const runs=(history.runs||[]), avg=Math.round(runs.reduce((a,r)=>a+r.wpm,0)/(runs.length||1)), best=Math.max(0,...runs.map(r=>r.wpm)); screen.innerHTML=`<section class="panel"><h1>History</h1><div class="resultGrid">${metric('saved runs',runs.length)}${metric('best wpm',best)}${metric('average wpm',avg)}${metric('avg accuracy',Math.round(runs.reduce((a,r)=>a+r.accuracy,0)/(runs.length||1))+'%')}</div><div class="choices"><button data-filter="all" class="pill active">All</button><button data-filter="speed" class="pill">Speed</button><button data-filter="study" class="pill">Study</button><button id="clearHist" class="ghost">Clear all</button></div><div id="runs"></div></section>`; const draw=f=>$('#runs').innerHTML=runs.filter(r=>f==='all'||r.mode===f).map(r=>`<article class="history"><h3>${html(r.userLabel||r.mode+' run')} <small>${new Date(r.createdAt).toLocaleString()}</small></h3><p>${r.wpm} WPM · ${r.accuracy}% accuracy · ${r.consistency}% consistency · vs avg ${r.wpm-avg>=0?'+':''}${r.wpm-avg}</p>${graph(r.graph||[],r.wpm)}<button data-del="${r.id}" class="ghost">Delete</button></article>`).join('')||'<p class="hint">No saved runs yet.</p>'; draw('all'); screen.querySelectorAll('[data-filter]').forEach(b=>b.onclick=()=>{screen.querySelectorAll('[data-filter]').forEach(x=>x.classList.remove('active'));b.classList.add('active');draw(b.dataset.filter)}); $('#runs').onclick=e=>{if(e.target.dataset.del){history.runs=history.runs.filter(r=>r.id!==e.target.dataset.del);save(HISTORY_KEY,history);renderHistory()}}; $('#clearHist').onclick=()=>confirm('Clear all saved SlapTap runs?')&&(history={version:1,runs:[]},save(HISTORY_KEY,history),renderHistory())}
function openSettings(){hidePhoneKeyboard();modal.innerHTML=`<div class="shade"><dialog open class="settingsDialog"><div class="settingsHead"><div><p class="eyebrow">customize</p><h2>Settings</h2></div><button id="closeSetTop" class="ghost iconBtn" aria-label="Close settings">×</button></div><div class="settingsGrid"><label>Theme<select id="theme">${Object.entries(THEMES).map(([t,label])=>`<option value="${t}" ${settings.theme===t?'selected':''}>${label}</option>`).join('')}</select></label><label>Keyboard sound<select id="soundEffect">${Object.entries(KEY_SOUNDS).map(([value,label])=>`<option value="${value}" ${settings.soundEffect===value?'selected':''}>${label}</option>`).join('')}</select></label><label class="volumeControl">Volume<input id="volume" type="range" min="0" max="1" step=".05" value="${settings.volume}"/></label></div><div class="settingsToggles">${['sound','keyboard','nextKey','liveWpm','liveAccuracy','reducedMotion'].map(k=>`<label><input type="checkbox" id="${k}" ${settings[k]?'checked':''}/><span>${k==='keyboard'?'Desktop keyboard':k==='nextKey'?'Next-key highlight':k==='liveWpm'?'Live WPM':k==='liveAccuracy'?'Live accuracy':k==='reducedMotion'?'Reduced motion':'Sound effects'}</span></label>`).join('')}</div><div class="settingsActions"><button id="testSound" class="ghost">Test good sound</button><button id="testWrongSound" class="ghost">Test wrong sound</button><button id="resetSet" class="ghost">Reset settings</button><button id="clearSetHist" class="ghost dangerBtn">Clear saved history</button><button id="closeSet" class="primary">Done</button></div></dialog></div>`; $('#theme').onchange=e=>{settings.theme=e.target.value;save(SETTINGS_KEY,settings);applyTheme()}; ['sound','keyboard','nextKey','liveWpm','liveAccuracy','reducedMotion'].forEach(k=>$(`#${k}`).onchange=e=>{settings[k]=e.target.checked;save(SETTINGS_KEY,settings);applyTheme(); if(session&&(k.startsWith('live')||k==='keyboard'))renderRun()}); $('#soundEffect').onchange=e=>{settings.soundEffect=e.target.value;settings.sound=settings.soundEffect!=='none';save(SETTINGS_KEY,settings);applyTheme();renderKeyboard();play('char','a');openSettings()}; $('#volume').oninput=e=>{settings.volume=Number(e.target.value);save(SETTINGS_KEY,settings)}; $('#volume').onchange=()=>play('char','a'); $('#testSound').onclick=()=>play('char','a'); $('#testWrongSound').onclick=()=>play('wrong','x'); $('#closeSetTop').onclick=closeSettings; $('#resetSet').onclick=()=>{settings={...defaults};save(SETTINGS_KEY,settings);applyTheme();openSettings()}; $('#clearSetHist').onclick=()=>confirm('Clear saved history?')&&(history={version:1,runs:[]},save(HISTORY_KEY,history)); $('#closeSet').onclick=closeSettings}
function closeSettings(){modal.innerHTML='';focusInput()}
function soundProfile(name){return ({metal:{body:920,ring:4200,noise:6200,decay:.085,tone:'triangle',gain:.52,hit:.010},plastic:{body:520,ring:2300,noise:3600,decay:.055,tone:'square',gain:.42,hit:.008},wood:{body:240,ring:1150,noise:1750,decay:.11,tone:'sine',gain:.58,hit:.012},aluminum:{body:1200,ring:6400,noise:7200,decay:.12,tone:'triangle',gain:.46,hit:.009},brass:{body:760,ring:5100,noise:4700,decay:.15,tone:'sine',gain:.5,hit:.011},thock:{body:155,ring:720,noise:1250,decay:.13,tone:'sine',gain:.72,hit:.015},blue:{body:680,ring:3400,noise:5200,decay:.07,tone:'square',gain:.55,hit:.006},brown:{body:430,ring:2100,noise:2800,decay:.065,tone:'triangle',gain:.44,hit:.009},linear:{body:360,ring:1700,noise:2400,decay:.045,tone:'sine',gain:.32,hit:.007},laptop:{body:760,ring:2600,noise:4300,decay:.04,tone:'triangle',gain:.34,hit:.005},typewriter:{body:1180,ring:5200,noise:7600,decay:.105,tone:'square',gain:.7,hit:.016},ceramic:{body:1100,ring:5600,noise:6200,decay:.095,tone:'sine',gain:.5,hit:.008},glass:{body:1350,ring:7600,noise:8200,decay:.18,tone:'triangle',gain:.38,hit:.007},rubber:{body:210,ring:900,noise:1500,decay:.075,tone:'sine',gain:.45,hit:.018},spacebar:{body:185,ring:880,noise:2100,decay:.18,tone:'triangle',gain:.7,hit:.02}})[name]||soundProfile('metal')}
function makeNoise(ctx,duration){const b=ctx.createBuffer(1,Math.max(1,ctx.sampleRate*duration),ctx.sampleRate), d=b.getChannelData(0); for(let i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*(1-i/d.length); return b}
function envGain(ctx,amount,start,attack,decay){const g=ctx.createGain(); g.gain.setValueAtTime(.0001,start); g.gain.linearRampToValueAtTime(amount,start+attack); g.gain.exponentialRampToValueAtTime(.0001,start+decay); return g}
function keySignature(key){const s=String(key||'char'); let h=2166136261; for(let i=0;i<s.length;i++){h^=s.charCodeAt(i); h=Math.imul(h,16777619)} const n=(h>>>0)/4294967295; return {pitch:.91+n*.18,ring:.86+(((h>>>8)&255)/255)*.28,brightness:.82+(((h>>>16)&255)/255)*.36,delay:.010+(((h>>>24)&255)/255)*.012,weight:.88+(((h>>>4)&255)/255)*.24}}
function keyModifier(kind,key){const special={space:{pitch:.72,ring:.68,brightness:.72,delay:.020,weight:1.32},backspace:{pitch:.58,ring:.78,brightness:.9,delay:.017,weight:1.15},enter:{pitch:.66,ring:.74,brightness:.82,delay:.019,weight:1.22},wrong:{pitch:.38,ring:.42,brightness:1.65,delay:.028,weight:1.75}}[kind]; if(special)return special; return keySignature(key)}
function impulse(ctx,out,{time,vol,freq,ring,noise,decay,tone='triangle',noiseQ=2}){const body=ctx.createOscillator(), bodyGain=envGain(ctx,vol,time,.001,decay); body.type=tone; body.frequency.setValueAtTime(freq*(.985+Math.random()*.03),time); body.frequency.exponentialRampToValueAtTime(Math.max(40,freq*.66),time+decay); body.connect(bodyGain).connect(out); body.start(time); body.stop(time+decay+.02);
  const r=ctx.createOscillator(), rf=ctx.createBiquadFilter(), rg=envGain(ctx,vol*.36,time+.004,.001,decay*1.35); r.type='sine'; r.frequency.setValueAtTime(ring*(.99+Math.random()*.02),time); rf.type='bandpass'; rf.frequency.value=ring; rf.Q.value=10; r.connect(rf).connect(rg).connect(out); r.start(time+.004); r.stop(time+decay*1.4);
  const n=ctx.createBufferSource(), nf=ctx.createBiquadFilter(), ng=envGain(ctx,vol*.72,time,.001,Math.max(.018,decay*.45)); n.buffer=makeNoise(ctx,decay); nf.type='bandpass'; nf.frequency.value=noise; nf.Q.value=noiseQ; n.connect(nf).connect(ng).connect(out); n.start(time); n.stop(time+decay)}
function playWrong(ctx,t,p,mod,vol,out){const thud=Math.max(70,p.body*.32*mod.pitch), crack=Math.max(420,p.ring*.48*mod.ring); impulse(ctx,out,{time:t,vol:vol*1.15*mod.weight,freq:thud,ring:crack,noise:p.noise*1.25*mod.brightness,decay:p.decay*1.5,tone:'sawtooth',noiseQ:1.15}); impulse(ctx,out,{time:t+.035,vol:vol*.55*mod.weight,freq:thud*.62,ring:crack*.55,noise:p.noise*.72,decay:p.decay*.9,tone:'triangle',noiseQ:.8})}
function playTypewriter(ctx,t,p,mod,vol,out){impulse(ctx,out,{time:t,vol:vol*.34*mod.weight,freq:p.body*1.85*mod.pitch,ring:p.ring*1.18*mod.ring,noise:p.noise*1.12*mod.brightness,decay:.024,tone:'triangle',noiseQ:3.4}); impulse(ctx,out,{time:t+mod.delay,vol:vol*mod.weight,freq:p.body*mod.pitch,ring:p.ring*mod.ring,noise:p.noise*mod.brightness,decay:p.decay,tone:p.tone,noiseQ:2.6})}
function play(kind,key=kind){if(!settings.sound||settings.soundEffect==='none')return; try{audio??=new (window.AudioContext||window.webkitAudioContext)(); if(audio.state==='suspended')audio.resume(); if(!audio._master){const comp=audio.createDynamicsCompressor(); comp.threshold.value=-20; comp.knee.value=22; comp.ratio.value=5; comp.attack.value=.002; comp.release.value=.14; comp.connect(audio.destination); audio._master=comp} const ctx=audio, t=ctx.currentTime, p=soundProfile(settings.soundEffect), mod=keyModifier(kind,key), vol=settings.volume*.18*p.gain, out=ctx.createGain(); out.gain.value=1; out.connect(audio._master); if(kind==='wrong'){playWrong(ctx,t,p,mod,vol,out);return} if(settings.soundEffect==='typewriter'){playTypewriter(ctx,t,p,mod,vol,out);return} impulse(ctx,out,{time:t,vol:vol*mod.weight,freq:p.body*mod.pitch,ring:p.ring*mod.ring,noise:p.noise*mod.brightness,decay:p.decay,tone:p.tone})}catch{}}
function openTestSettings(){hidePhoneKeyboard();modal.innerHTML=`<div class="shade"><dialog open class="settingsDialog"><div class="settingsHead"><div><p class="eyebrow">test</p><h2>Change test</h2><p class="hint">This test length applies everywhere: Speed runs and Study/notes tests.</p></div><button id="closeTestTop" class="ghost iconBtn" aria-label="Close change test">×</button></div><div class="settingsGrid"><label>Test type<select id="globalType"><option value="time" ${speedGoal.type==='time'?'selected':''}>Time</option><option value="words" ${speedGoal.type==='words'?'selected':''}>Words</option></select></label><label class="globalTime">Time<select id="globalDuration">${DURATIONS.map(d=>`<option value="${d}" ${speedGoal.duration===d?'selected':''}>${d}s</option>`).join('')}</select></label><label class="globalWords">Words<select id="globalWords">${SPEED_WORDS.map(w=>`<option value="${w}" ${speedGoal.words===w?'selected':''}>${w} words</option>`).join('')}</select></label><label>Capitals<select id="globalCaps"><option value="lower" ${speedGoal.caps==='lower'?'selected':''}>remove capitals</option><option value="keep" ${speedGoal.caps==='keep'?'selected':''}>keep original</option><option value="upper" ${speedGoal.caps==='upper'?'selected':''}>ALL CAPITALS</option></select></label></div><div class="settingsToggles"><label><input id="globalPunctuation" type="checkbox" ${speedGoal.punctuation?'checked':''}/><span>Punctuation</span></label><label><input id="globalNumbers" type="checkbox" ${speedGoal.numbers?'checked':''}/><span>Numbers</span></label></div><div class="settingsActions"><button id="resetTest" class="ghost">Reset to 30 seconds</button><button id="startNewTest" class="primary">Start ${currentTestLabel()} test</button></div></dialog></div>`; const sync=()=>{document.querySelector('.globalTime').style.display=speedGoal.type==='time'?'block':'none';document.querySelector('.globalWords').style.display=speedGoal.type==='words'?'block':'none';$('#startNewTest').textContent=`Start ${currentTestLabel()} test`}; sync(); $('#globalType').onchange=e=>{speedGoal.type=e.target.value;saveTest();sync()}; $('#globalDuration').onchange=e=>{speedGoal.duration=Number(e.target.value);saveTest();sync()}; $('#globalWords').onchange=e=>{speedGoal.words=Number(e.target.value);saveTest();sync()}; $('#globalCaps').onchange=e=>{speedGoal.caps=e.target.value;saveTest()}; $('#globalPunctuation').onchange=e=>{speedGoal.punctuation=e.target.checked;saveTest()}; $('#globalNumbers').onchange=e=>{speedGoal.numbers=e.target.checked;saveTest()}; $('#resetTest').onclick=()=>{speedGoal={type:'time',duration:30,words:25,caps:'lower',punctuation:false,numbers:true}; study={...study,caps:'lower',punctuation:false};saveTest();openTestSettings()}; $('#startNewTest').onclick=()=>{closeSettings(); if(view==='study'&&study.text)begin(studyRunConfig()); else {view='speed';startSpeed()}}; $('#closeTestTop').onclick=closeSettings}
function initSettingsButton(){const b=$('#settingsButton'), t=$('#testButton'); if(b)b.addEventListener('click',openSettings); if(t)t.addEventListener('click',openTestSettings)}
